-- 1. SalesChannel: SELLIC (id=16)
VALUES (16, 'SELLIC', 'ACTIVE', NOW(), NOW())
ON DUPLICATE KEY UPDATE channel_name = VALUES(channel_name);

-- 2. Shop: 셀릭 단일 샵 (API 자격증명은 운영팀이 별도 세팅)
VALUES (16, 'SELLIC', 'sellic-default', 'ACTIVE', 'SELLIC', NOW(), NOW())
ON DUPLICATE KEY UPDATE shop_name = VALUES(shop_name);

SET @shop_id = (SELECT id FROM shop WHERE sales_channel_id = 16 AND account_id = 'sellic-default' LIMIT 1);

